DELETE FROM foods
WHERE id BETWEEN '018f0000-0000-7000-8002-000000000101'::uuid
             AND '018f0000-0000-7000-8002-000000000118'::uuid;

ALTER TABLE foods DROP COLUMN IF EXISTS image_url;
